import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';
import { Vex } from '@vex/sdk';

const bedrock = new BedrockAgentRuntimeClient({ region: 'us-east-1' });
const vex = new Vex({ apiKey: 'your-vex-api-key' });

const sessionState = { parentalConsent: true, studentId: 'STU123', grade: 10 };

const command = new InvokeAgentCommand({
  agentId: 'EDU_AGENT_ID',
  agentAliasId: 'TSTALIAS',
  sessionId: 'session-789',
  inputText: 'Help with algebra homework',
  sessionState: JSON.stringify(sessionState)
});

const response = await bedrock.send(command);
const agentResponse = response.completion;

// Vex verification with accessibility + consent checks
const result = await vex.verify({
  messages: [{ role: 'assistant', content: agentResponse }],
  policy: 'vex://policies/education-accessibility-ferpa',
  context: { ...sessionState, section508: true }
});

if (result.status === 'approved') {
  console.log(result.output);
} else {
  console.log('Blocked: Accessibility or consent violation');
}
